#include <bits/stdc++.h>
using namespace std;

const int N=1e4+4;

int n,m,head[N],ver[10*N],nxt[10*N],tot,path[10*N],cnt;
int sys[10*N],top1;

void add(int x,int y){
    ver[++tot]=y,nxt[tot]=head[x],head[x]=tot;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,u,v;i<=m;i++){
        scanf("%d%d",&u,&v);
        add(u,v);
        add(v,u);
    }
    sys[++top1]=1;
    while(top1){
        int x=sys[top1];
        if(head[x]){
            sys[++top1]=ver[head[x]];
            head[x]=nxt[head[x]];
        }else{
            path[++cnt]=sys[top1--];
        }
    }
    for(int i=1;i<=cnt;i++)
        printf("%d\n",path[i]);
    return 0;
}
